1	import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
2	import {
3	  Pressable,
4	  RefreshControl,
5	  SafeAreaView,
6	  ScrollView,
7	  StyleSheet,
8	  Text,
9	  View,
10	} from 'react-native';
11	import { StatusPill, type StatusPillStatus } from '@/components/primitives/StatusPill';
12	import { SkeletonCard } from '@/components/primitives/SkeletonCard';
13	import { useToast } from '@/components/primitives/Toast';
14	import { colors, radii, shadows, spacing } from '@/design/tokens';
15	import { fontFamilies, textStyles } from '@/design/typography';
16	import { useAuth } from '@/lib/auth';
17	import { getCachedToken } from '@/lib/storage';
18	import { supabase } from '@/lib/supabase';
19	import { formatRelativeTime } from '@/lib/time';
20	import type { Database } from '@/types/supabase';
21	
22	// US-056 — Lister Inbox, Applications sub-tab. Calls the
23	// `list_my_applications_as_lister` SECURITY DEFINER RPC (companion migration
24	// `us_056_list_my_applications_as_lister_rpc`) which joins applications →
25	// listings → users → creator_profiles → social_links under an explicit
26	// `listings.lister_id = current_user_id()` ownership gate and returns one
27	// flat row per application — creator username + platform handles + follower
28	// counts + IG avg views + pitch preview. Same list-my-rows pattern as
29	// US-043 / US-054 (Codebase Pattern #118).
30	//
31	// Segments: Pending / Approved / Rejected per AC. The RPC already excludes
32	// withdrawn + cancelled_listing_edit + cancelled_listing_closed — those are
33	// creator-initiated or cascade-driven cancellations that don't require
34	// lister review. They surface on the campaign-scoped detail screen
35	// (US-057+), not the inbox.
36	//
37	// Grouping: per docs/design.md §3.2 the inbox groups rows by campaign with
38	// inline SectionHeader separators. The RPC returns rows in
39	// `created_at desc`, so within each group rows remain recency-ordered; the
40	// group order is driven by the most-recent application within each group.
41	//
42	// Realtime INSERT subscription: applications is already in the
43	// supabase_realtime publication (US-044). We subscribe with no client
44	// filter because applications has no lister_id column — the
45	// `applications_lister_read` RLS policy is the join-through-listings
46	// security boundary (Codebase Pattern #123). Because the raw INSERT
47	// payload lacks the joined creator + platform metrics, on each insert we
48	// re-run the RPC rather than patching locally. A toast ("New application
49	// received", info variant) gives the lister an in-app cue.
50	
51	type ApplicationStatus = Database['public']['Enums']['application_status'];
52	type Segment = 'pending' | 'approved' | 'rejected';
53	type Row = Database['public']['Functions']['list_my_applications_as_lister']['Returns'][number];
54	
55	// Compile-time exhaustive mapping: if a new enum value is added the
56	// compiler flags the missing bucket (Codebase Pattern #121). The three
57	// enum values the RPC filters out are intentionally absent — they cannot
58	// reach this screen.
59	const STATUS_BUCKET: Record<
60	  Exclude<
61	    ApplicationStatus,
62	    'withdrawn' | 'cancelled_listing_edit' | 'cancelled_listing_closed'
63	  >,
64	  Segment
65	> = {
66	  pending: 'pending',
67	  approved: 'approved',
68	  rejected: 'rejected',
69	};
70	
71	const SEGMENTS: readonly { key: Segment; label: string }[] = [
72	  { key: 'pending', label: 'Pending' },
73	  { key: 'approved', label: 'Approved' },
74	  { key: 'rejected', label: 'Rejected' },
75	];
76	
77	type SegmentControlProps = {
78	  active: Segment;
79	  counts: Record<Segment, number>;
80	  onChange: (next: Segment) => void;
81	};
82	
83	function SegmentControl({ active, counts, onChange }: SegmentControlProps) {
84	  return (
85	    <View style={styles.segmentRow} accessibilityRole="tablist">
86	      {SEGMENTS.map((s) => (
87	        <SegmentButton
88	          key={s.key}
89	          label={`${s.label} (${counts[s.key]})`}
90	          selected={active === s.key}
91	          onPress={() => onChange(s.key)}
92	          testID={`segment-${s.key}`}
93	        />
94	      ))}
95	    </View>
96	  );
97	}
98	
99	type SegmentButtonProps = {
100	  label: string;
101	  selected: boolean;
102	  onPress: () => void;
103	  testID?: string;
104	};
105	
106	function SegmentButton({ label, selected, onPress, testID }: SegmentButtonProps) {
107	  const bg = selected ? colors.primarySoft : colors.surface;
108	  const textColor = selected ? colors.primaryDeep : colors.ink;
109	  return (
110	    <Pressable
111	      onPress={onPress}
112	      accessibilityRole="tab"
113	      accessibilityState={{ selected }}
114	      accessibilityLabel={label}
115	      style={[styles.segment, { backgroundColor: bg }, shadows.hard]}
116	      testID={testID}
117	    >
118	      <Text style={[textStyles.micro, { color: textColor }]} allowFontScaling={false}>
119	        {label}
120	      </Text>
121	    </Pressable>
122	  );
123	}
124	
125	// SectionHeader per docs/design.md §6 — kept inline until a second consumer
126	// shows up. The `══════ Label ══════` visual uses horizontal rules bracketing
127	// the title; a single flex row with 2-px borders keeps it token-friendly.
128	function SectionHeader({ title }: { title: string }) {
129	  return (
130	    <View style={styles.sectionHeaderRow} accessibilityRole="header">
131	      <View style={styles.sectionRule} />
132	      <Text
133	        style={[textStyles.micro, { color: colors.ink }]}
134	        allowFontScaling={false}
135	        numberOfLines={1}
136	      >
137	        {title}
138	      </Text>
139	      <View style={styles.sectionRule} />
140	    </View>
141	  );
142	}
143	
144	function bucketFor(status: ApplicationStatus): Segment | null {
145	  if (status === 'withdrawn') return null;
146	  if (status === 'cancelled_listing_edit') return null;
147	  if (status === 'cancelled_listing_closed') return null;
148	  return STATUS_BUCKET[status];
149	}
150	
151	export default function ListerInboxApplications() {
152	  const { user } = useAuth();
153	  const userId = user?.id ?? null;
154	  const { show: showToast } = useToast();
155	
156	  const [segment, setSegment] = useState<Segment>('pending');
157	  const [rows, setRows] = useState<Row[]>([]);
158	  const [loading, setLoading] = useState(true);
159	  const [refreshing, setRefreshing] = useState(false);
160	  const [error, setError] = useState<string | null>(null);
161	
162	  const load = useCallback(async () => {
163	    if (!userId) return;
164	    setError(null);
165	    const { data, error: rpcError } = await supabase.rpc('list_my_applications_as_lister');
166	    if (rpcError) {
167	      setError("Couldn't load applications.");
168	      setRows([]);
169	    } else {
170	      setRows(data ?? []);
171	    }
172	  }, [userId]);
173	
174	  // Mirror `load` through a ref so the realtime effect can call the latest
175	  // closure without re-subscribing every time `load` re-creates. Same
176	  // pattern as the creator realtime handler (Codebase Pattern #82/#106).
177	  const loadRef = useRef(load);
178	  useEffect(() => {
179	    loadRef.current = load;
180	  }, [load]);
181	
182	  useEffect(() => {
183	    setLoading(true);
184	    void load().finally(() => setLoading(false));
185	  }, [load]);
186	
187	  const onRefresh = useCallback(async () => {
188	    setRefreshing(true);
189	    await load();
190	    setRefreshing(false);
191	  }, [load]);
192	
193	  // Realtime INSERT subscription. No client-side filter: applications has
194	  // no lister_id column to filter on, and `applications_lister_read` RLS is
195	  // the authoritative boundary (the broker drops any row the caller can't
196	  // SELECT). supabase.realtime.setAuth(token) mirrors the US-036 +
197	  // US-044 pattern for authenticated websockets (Codebase Pattern #105).
198	  useEffect(() => {
199	    if (!userId) return;
200	    const token = getCachedToken();
201	    if (!token) return;
202	    let cancelled = false;
203	    let activeChannel: ReturnType<typeof supabase.channel> | null = null;
204	    void supabase.realtime.setAuth(token).then(() => {
205	      if (cancelled) return;
206	      activeChannel = supabase
207	        .channel(`lister-inbox-applications-${userId}`)
208	        .on(
209	          'postgres_changes',
210	          {
211	            event: 'INSERT',
212	            schema: 'public',
213	            table: 'applications',
214	          },
215	          () => {
216	            void loadRef.current();
217	            showToast({
218	              message: 'New application received',
219	              variant: 'info',
220	            });
221	          },
222	        )
223	        .subscribe();
224	    });
225	    return () => {
226	      cancelled = true;
227	      if (activeChannel) void supabase.removeChannel(activeChannel);
228	    };
229	  }, [userId, showToast]);
230	
231	  const byBucket = useMemo(() => {
232	    const map: Record<Segment, Row[]> = { pending: [], approved: [], rejected: [] };
233	    for (const r of rows) {
234	      const b = bucketFor(r.status);
235	      if (b) map[b].push(r);
236	    }
237	    return map;
238	  }, [rows]);
239	
240	  const counts = useMemo<Record<Segment, number>>(
241	    () => ({
242	      pending: byBucket.pending.length,
243	      approved: byBucket.approved.length,
244	      rejected: byBucket.rejected.length,
245	    }),
246	    [byBucket],
247	  );
248	
249	  const grouped = useMemo(() => groupByListing(byBucket[segment]), [byBucket, segment]);
250	  const visibleCount = byBucket[segment].length;
251	
252	  return (
253	    <SafeAreaView style={styles.root}>
254	      <ScrollView
255	        contentContainerStyle={styles.scroll}
256	        refreshControl={
257	          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor={colors.ink} />
258	        }
259	      >
260	        <Text style={[textStyles.display, styles.header]}>Inbox</Text>
261	        <SegmentControl active={segment} counts={counts} onChange={setSegment} />
262	
263	        {loading ? (
264	          <View style={styles.list} testID="applications-loading">
265	            <SkeletonCard />
266	            <SkeletonCard />
267	          </View>
268	        ) : error ? (
269	          <View style={styles.emptyBox}>
270	            <Text style={[textStyles.body, { color: colors.danger }]}>{error}</Text>
271	          </View>
272	        ) : visibleCount === 0 ? (
273	          <View style={styles.emptyBox} testID={`applications-empty-${segment}`}>
274	            <Text style={[textStyles.body, { color: colors.ink70, textAlign: 'center' }]}>
275	              {emptyMessageFor(segment)}
276	            </Text>
277	          </View>
278	        ) : (
279	          <View style={styles.list}>
280	            {grouped.map((group) => (
281	              <View key={group.listingId} style={styles.group}>
282	                <SectionHeader title={group.listingTitle} />
283	                {group.rows.map((row) => (
284	                  <ApplicationInboxRow key={row.application_id} row={row} />
285	                ))}
286	              </View>
287	            ))}
288	          </View>
289	        )}
290	      </ScrollView>
291	    </SafeAreaView>
292	  );
293	}
294	
295	function emptyMessageFor(segment: Segment): string {
296	  switch (segment) {
297	    case 'pending':
298	      return 'No pending applications. New applications will land here in real time.';
299	    case 'approved':
300	      return 'No approvals yet.';
301	    case 'rejected':
302	      return 'No rejections yet.';
303	  }
304	}
305	
306	type ListingGroup = { listingId: string; listingTitle: string; rows: Row[] };
307	
308	function groupByListing(rows: Row[]): ListingGroup[] {
309	  const order: string[] = [];
310	  const by = new Map<string, ListingGroup>();
311	  for (const r of rows) {
312	    let g = by.get(r.listing_id);
313	    if (!g) {
314	      g = { listingId: r.listing_id, listingTitle: r.listing_title, rows: [] };
315	      by.set(r.listing_id, g);
316	      order.push(r.listing_id);
317	    }
318	    g.rows.push(r);
319	  }
320	  return order.map((id) => by.get(id)!);
321	}
322	
323	function ApplicationInboxRow({ row }: { row: Row }) {
324	  const pillStatus: StatusPillStatus =
325	    row.status === 'pending' || row.status === 'approved' || row.status === 'rejected'
326	      ? row.status
327	      : 'cancelled';
328	  const relative = formatRelativeTime(new Date(row.created_at));
329	  const pitch = row.cover_note?.trim() ?? '';
330	
331	  return (
332	    <View
333	      style={[styles.card, shadows.hard]}
334	      accessibilityLabel={`Application from ${row.creator_username}, ${pillStatus}, applied ${relative}`}
335	      testID={`application-${row.application_id}`}
336	    >
337	      <View style={styles.cardTopRow}>
338	        <Text style={[textStyles.h2, { color: colors.ink }]} numberOfLines={1}>
339	          @{row.creator_username}
340	        </Text>
341	        <StatusPill status={pillStatus} />
342	      </View>
343	
344	      <View style={styles.metricsBlock}>
345	        <MetricLine
346	          platform="TikTok"
347	          handle={row.tiktok_handle}
348	          primary={row.tiktok_follower_count}
349	          primaryLabel="followers"
350	          testID={`metrics-tiktok-${row.application_id}`}
351	        />
352	        <MetricLine
353	          platform="Instagram"
354	          handle={row.instagram_handle}
355	          primary={row.instagram_follower_count}
356	          primaryLabel="followers"
357	          secondary={row.instagram_avg_views_last_10}
358	          secondaryLabel="avg views"
359	          testID={`metrics-ig-${row.application_id}`}
360	        />
361	      </View>
362	
363	      {pitch ? (
364	        <Text
365	          style={[textStyles.body, { color: colors.ink70 }]}
366	          numberOfLines={2}
367	          testID={`pitch-${row.application_id}`}
368	        >
369	          {pitch}
370	        </Text>
371	      ) : null}
372	
373	      <Text style={[textStyles.caption, { color: colors.ink70 }]}>Applied {relative}</Text>
374	    </View>
375	  );
376	}
377	
378	type MetricLineProps = {
379	  platform: string;
380	  handle: string | null;
381	  primary: number | null;
382	  primaryLabel: string;
383	  secondary?: number | null;
384	  secondaryLabel?: string;
385	  testID?: string;
386	};
387	
388	function MetricLine({
389	  platform,
390	  handle,
391	  primary,
392	  primaryLabel,
393	  secondary,
394	  secondaryLabel,
395	  testID,
396	}: MetricLineProps) {
397	  if (!handle) {
398	    return (
399	      <View style={styles.metricRow} testID={testID}>
400	        <Text style={[textStyles.caption, { color: colors.ink70, width: 80 }]}>{platform}</Text>
401	        <Text style={[textStyles.caption, { color: colors.ink70 }]}>no handle linked</Text>
402	      </View>
403	    );
404	  }
405	  return (
406	    <View style={styles.metricRow} testID={testID}>
407	      <Text style={[textStyles.caption, { color: colors.ink70, width: 80 }]}>{platform}</Text>
408	      <Text style={styles.metricHandle} allowFontScaling={false} numberOfLines={1}>
409	        @{handle}
410	      </Text>
411	      <Text style={[textStyles.caption, { color: colors.ink }]}>
412	        {formatCount(primary)} {primaryLabel}
413	        {secondary != null && secondaryLabel
414	          ? ` · ${formatCount(secondary)} ${secondaryLabel}`
415	          : ''}
416	      </Text>
417	    </View>
418	  );
419	}
420	
421	// Compact thousands formatter: 12_345 → "12.3K", 1_200_000 → "1.2M". Keeps
422	// inbox rows dense and matches the other social-metric callouts on the
423	// discover + detail screens.
424	function formatCount(n: number | null): string {
425	  if (n == null) return '—';
426	  if (n < 1_000) return n.toLocaleString('en-US');
427	  if (n < 1_000_000) return `${(n / 1_000).toFixed(n < 10_000 ? 1 : 0)}K`;
428	  return `${(n / 1_000_000).toFixed(n < 10_000_000 ? 1 : 0)}M`;
429	}
